import { describe, it, expect } from "vitest";
import { quote, claim, createPolicy } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote - basic functionality", () => {
    it.todo("should return 0 premium for empty item list");
    it.todo("should return base premium for single sword");
    it.todo("should return base premium for single amulet");
    it.todo("should return base premium for single staff");
    it.todo("should return base premium for single potion");
    it.todo("should sum premiums for two different items");
    it.todo("should sum premiums for multiple items");
    it.todo("should calculate base premium for single component");
    it.todo("should calculate discounted premium for three identical components");
    it.todo("should sum premiums correctly with mixed items and components");
  });

  describe("claim - basic functionality", () => {
    it.todo("should reject claim on non-existent policy");
    it.todo("should apply 100G deductible to damage claim");
    it.todo("should return 0 payout when damage equals deductible");
    it.todo("should cap payout at 2x insurance sum");
    it.todo("should process valid claim with payout after deductible");
  });
});

export interface Item {
  type: "sword" | "amulet" | "staff" | "potion" | "component";
  count?: number;
}

export interface Policy {
  id: string;
  premiumSum: number;
